    42→// ErrorUnaryInterceptor intercepts known errors and returns the appropriate GRPC status code
    43→func ErrorUnaryInterceptor(ctx context.Context, req interface{}, _ *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (resp interface{}, err error) {
    44→	resp, err = handler(ctx, req)
    45→	if err == nil {
    46→		return resp, nil
    47→	}
    48→
    49→	metrics.ErrorsTotal.Add(ctx, 1)
    50→
    51→	// given already a *status.Error then forward unchanged
    52→	if _, ok := status.FromError(err); ok {
    53→		return
    54→	}
    55→
    56→	if errors.Is(err, context.Canceled) {
    57→		err = status.Error(codes.Canceled, err.Error())
    58→		return
    59→	}
