   576→// x-flipt-accept-server-version represents the maximum version of the flipt server that the client can handle.
   577→const fliptAcceptServerVersionHeaderKey = "x-flipt-accept-server-version"
   578→
   579→type fliptServerVersionContextKey struct{}
