   581→// WithFliptAcceptServerVersion sets the flipt version in the context.
   582→func WithFliptAcceptServerVersion(ctx context.Context, version semver.Version) context.Context {
   583→	return context.WithValue(ctx, fliptServerVersionContextKey{}, version)
   584→}
   585→
   586→// The last version that does not support the x-flipt-accept-server-version header.
   587→var preFliptAcceptServerVersion = semver.MustParse("1.37.1")
   588→
   589→// FliptAcceptServerVersionFromContext returns the flipt-accept-server-version from the context if it exists or the default version.
   590→func FliptAcceptServerVersionFromContext(ctx context.Context) semver.Version {
   591→	v, ok := ctx.Value(fliptServerVersionContextKey{}).(semver.Version)
   592→	if !ok {
   593→		return preFliptAcceptServerVersion
   594→	}
   595→	return v
   596→}
   597→
   598→// FliptAcceptServerVersionUnaryInterceptor is a grpc client interceptor that sets the flipt-accept-server-version in the context if provided in the metadata/header.
   599→func FliptAcceptServerVersionUnaryInterceptor(logger *zap.Logger) grpc.UnaryServerInterceptor {
   600→	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
   601→		md, ok := metadata.FromIncomingContext(ctx)
   602→		if !ok {
   603→			return handler(ctx, req)
   604→		}
   605→
   606→		if fliptVersionHeader := md.Get(fliptAcceptServerVersionHeaderKey); len(fliptVersionHeader) > 0 {
   607→			version := fliptVersionHeader[0]
   608→			if version != "" {
   609→				cv, err := semver.ParseTolerant(version)
   610→				if err != nil {
   611→					logger.Warn("parsing x-flipt-accept-server-version header", zap.String("version", version), zap.Error(err))
   612→					return handler(ctx, req)
   613→				}
   614→
   615→				logger.Debug("x-flipt-accept-server-version header", zap.String("version", version))
   616→				ctx = WithFliptAcceptServerVersion(ctx, cv)
   617→			}
   618→		}
   619→
   620→		return handler(ctx, req)
   621→	}
   622→}
